func (kp *rsaKeyPair) sign(t *testing.T, claims jwt.Claims) string {
	t.Helper()
	tok := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	tok.Header["kid"] = kp.keyID
	raw, err := tok.SignedString(kp.private)
	require.NoError(t, err)
	return raw
}

