package middleware

import (
	"crypto/sha256"
	"encoding/json"
	"fmt"
	"net/http"
	"net/http/httptest"
	"strconv"
	"testing"
	"time"

	"github.com/alicebob/miniredis/v2"
	"github.com/gin-gonic/gin"
	"github.com/redis/go-redis/v9"
)

// newTestRateLimiter starts a miniredis instance and returns a RateLimiter
// backed by it, along with a cleanup function.
func newTestRateLimiter(t *testing.T) (*RateLimiter, *miniredis.Miniredis) {
	t.Helper()
	mr := miniredis.RunT(t)
	client := redis.NewClient(&redis.Options{Addr: mr.Addr()})
	rl := NewRateLimiter(client, nil)
	return rl, mr
}

// newRateLimitRouter builds a minimal Gin router that applies the given
// middleware and always responds 200 OK.
func newRateLimitRouter(mw gin.HandlerFunc) *gin.Engine {
	gin.SetMode(gin.TestMode)
	r := gin.New()
	r.Use(mw)
	r.GET("/test", func(c *gin.Context) {
		c.JSON(http.StatusOK, gin.H{"ok": true})
	})
	return r
}

// doRequest fires a GET /test against the router and returns the recorder.
func doRequest(r *gin.Engine) *httptest.ResponseRecorder {
	w := httptest.NewRecorder()
	req := httptest.NewRequest(http.MethodGet, "/test", nil)
	r.ServeHTTP(w, req)
	return w
}

// ── TestRateLimitBasic ───────────────────────────────────────────────────────

// TestRateLimitBasic verifies that requests under the limit are admitted and
// that the X-RateLimit-* headers are present on every response.
func TestRateLimitBasic(t *testing.T) {
	rl, _ := newTestRateLimiter(t)

	mw := RateLimitMiddleware(rl, 5, func(c *gin.Context) string {
		return "raven:rl:test:basic"
	})
	r := newRateLimitRouter(mw)

	for i := 1; i <= 5; i++ {
		w := doRequest(r)
		if w.Code != http.StatusOK {
			t.Fatalf("request %d: expected 200, got %d", i, w.Code)
		}
		if w.Header().Get("X-RateLimit-Limit") != "5" {
			t.Errorf("request %d: X-RateLimit-Limit missing or wrong", i)
		}
		if w.Header().Get("X-RateLimit-Remaining") == "" {
			t.Errorf("request %d: X-RateLimit-Remaining missing", i)
		}
		if w.Header().Get("X-RateLimit-Reset") == "" {
			t.Errorf("request %d: X-RateLimit-Reset missing", i)
		}
	}
}

// TestRateLimitExceeded verifies that the (limit+1)th request is rejected with
// 429 and the correct JSON body + Retry-After header.
func TestRateLimitExceeded(t *testing.T) {
	rl, _ := newTestRateLimiter(t)

	const limit = 3
	mw := RateLimitMiddleware(rl, limit, func(c *gin.Context) string {
		return "raven:rl:test:exceeded"
	})
	r := newRateLimitRouter(mw)

	// Exhaust the limit.
	for i := 0; i < limit; i++ {
		w := doRequest(r)
		if w.Code != http.StatusOK {
			t.Fatalf("request %d should succeed, got %d", i+1, w.Code)
		}
	}

	// Next request should be rejected.
	w := doRequest(r)
	if w.Code != http.StatusTooManyRequests {
		t.Fatalf("expected 429, got %d", w.Code)
	}
	if w.Header().Get("Retry-After") == "" {
		t.Error("expected Retry-After header on 429 response")
	}

	var body map[string]interface{}
	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
		t.Fatalf("failed to decode 429 body: %v", err)
	}
	if body["error"] != "rate_limit_exceeded" {
		t.Errorf("expected error=rate_limit_exceeded, got %v", body["error"])
	}
	if body["retry_after"] == nil {
		t.Error("expected retry_after field in 429 body")
	}

	// Near-boundary assertion: X-RateLimit-Reset must be a Unix timestamp
	// within [now, now+60] seconds — i.e. within the current 1-minute window.
	resetStr := w.Header().Get("X-RateLimit-Reset")
	if resetStr == "" {
		t.Fatal("expected X-RateLimit-Reset header on 429 response")
	}
	resetTs, err := strconv.ParseInt(resetStr, 10, 64)
	if err != nil {
		t.Fatalf("X-RateLimit-Reset is not a valid int64: %q", resetStr)
	}
	now := time.Now().Unix()
	if resetTs < now || resetTs > now+60 {
		t.Errorf("X-RateLimit-Reset %d is not within [now(%d), now+60(%d)]", resetTs, now, now+60)
	}
}

// TestRateLimitWindowReset verifies that the sliding window allows requests
// again after time has advanced past the window.
func TestRateLimitWindowReset(t *testing.T) {
	rl, mr := newTestRateLimiter(t)

	const limit = 2
	mw := RateLimitMiddleware(rl, limit, func(c *gin.Context) string {
		return "raven:rl:test:window"
	})
	r := newRateLimitRouter(mw)

	// Exhaust the limit.
	for i := 0; i < limit; i++ {
		w := doRequest(r)
		if w.Code != http.StatusOK {
			t.Fatalf("request %d should succeed, got %d", i+1, w.Code)
		}
	}

	// Verify we're now blocked.
	w := doRequest(r)
	if w.Code != http.StatusTooManyRequests {
		t.Fatalf("expected 429, got %d", w.Code)
	}

	// Fast-forward miniredis clock by 61 seconds so all sorted-set members
	// fall outside the 60-second window.
	mr.FastForward(61 * time.Second)

	// The window has reset; a new request should succeed.
	w = doRequest(r)
	if w.Code != http.StatusOK {
		t.Fatalf("after window reset expected 200, got %d", w.Code)
	}
}

// TestRateLimitValkeyFailureFallback verifies that when Valkey is unavailable
// the middleware admits the request (fail-open) rather than returning an error,
// and that all required X-RateLimit-* headers are still present on the response.
func TestRateLimitValkeyFailureFallback(t *testing.T) {
	rl, mr := newTestRateLimiter(t)

	// Close miniredis to simulate Valkey being down.
	mr.Close()

	mw := RateLimitMiddleware(rl, 1, func(c *gin.Context) string {
		return "raven:rl:test:failure"
	})
	r := newRateLimitRouter(mw)

	w := doRequest(r)
	if w.Code != http.StatusOK {
		t.Fatalf("expected fail-open (200) when Valkey is unavailable, got %d", w.Code)
	}
	if w.Header().Get("X-RateLimit-Limit") == "" {
		t.Error("expected X-RateLimit-Limit header in fail-open path")
	}
	if w.Header().Get("X-RateLimit-Remaining") == "" {
		t.Error("expected X-RateLimit-Remaining header in fail-open path")
	}
	if w.Header().Get("X-RateLimit-Reset") == "" {
		t.Error("expected X-RateLimit-Reset header in fail-open path")
	}
}

// TestRateLimitDifferentKeysIndependent verifies that two different keys have
// independent counters.
func TestRateLimitDifferentKeysIndependent(t *testing.T) {
	rl, _ := newTestRateLimiter(t)

	const limit = 2

	makeRouter := func(key string) *gin.Engine {
		mw := RateLimitMiddleware(rl, limit, func(c *gin.Context) string {
			return key
		})
		return newRateLimitRouter(mw)
	}

	r1 := makeRouter("raven:rl:test:keyA")
	r2 := makeRouter("raven:rl:test:keyB")

	// Exhaust key A.
	for i := 0; i < limit; i++ {
		doRequest(r1)
	}

	// Key A is now blocked.
	w := doRequest(r1)
	if w.Code != http.StatusTooManyRequests {
		t.Fatalf("keyA: expected 429, got %d", w.Code)
	}

	// Key B should still be freely accessible.
	w = doRequest(r2)
	if w.Code != http.StatusOK {
		t.Fatalf("keyB: expected 200, got %d", w.Code)
	}
}

// TestRateLimitRemainingDecrement checks that X-RateLimit-Remaining decreases
// with each request.
func TestRateLimitRemainingDecrement(t *testing.T) {
	rl, _ := newTestRateLimiter(t)

	const limit = 5
	mw := RateLimitMiddleware(rl, limit, func(c *gin.Context) string {
		return "raven:rl:test:decrement"
	})
	r := newRateLimitRouter(mw)

	prev := limit
	for i := 0; i < limit; i++ {
		w := doRequest(r)
		if w.Code != http.StatusOK {
			t.Fatalf("request %d: expected 200, got %d", i+1, w.Code)
		}
		rem, err := strconv.Atoi(w.Header().Get("X-RateLimit-Remaining"))
		if err != nil {
			t.Fatalf("request %d: could not parse X-RateLimit-Remaining: %v", i+1, err)
		}
		if rem >= prev {
			t.Errorf("request %d: remaining should decrease; prev=%d, got=%d", i+1, prev, rem)
		}
		prev = rem
	}
}

// TestByUserID verifies the ByUserID convenience wrapper uses the correct key
// prefix and admits/blocks accordingly.
func TestByUserID(t *testing.T) {
	rl, _ := newTestRateLimiter(t)

	const limit = 2

	gin.SetMode(gin.TestMode)
	r := gin.New()
	// Inject user_id into gin context before the rate-limit middleware.
	r.Use(func(c *gin.Context) {
		c.Set(ContextKeyUserID, "user-abc")
		c.Next()
	})
	r.Use(ByUserID(rl, limit))
	r.GET("/test", func(c *gin.Context) { c.Status(http.StatusOK) })

	for i := 0; i < limit; i++ {
		w := doRequest(r)
		if w.Code != http.StatusOK {
			t.Fatalf("ByUserID request %d: expected 200, got %d", i+1, w.Code)
		}
	}
	w := doRequest(r)
	if w.Code != http.StatusTooManyRequests {
		t.Fatalf("ByUserID: expected 429 after limit, got %d", w.Code)
	}
}

// TestByOrgID verifies the ByOrgID convenience wrapper.
func TestByOrgID(t *testing.T) {
	rl, _ := newTestRateLimiter(t)

	const limit = 2

	gin.SetMode(gin.TestMode)
	r := gin.New()
	r.Use(func(c *gin.Context) {
		c.Set(ContextKeyOrgID, "org-xyz")
		c.Next()
	})
	r.Use(ByOrgID(rl, limit))
	r.GET("/test", func(c *gin.Context) { c.Status(http.StatusOK) })

	for i := 0; i < limit; i++ {
		w := doRequest(r)
		if w.Code != http.StatusOK {
			t.Fatalf("ByOrgID request %d: expected 200, got %d", i+1, w.Code)
		}
	}
	w := doRequest(r)
	if w.Code != http.StatusTooManyRequests {
		t.Fatalf("ByOrgID: expected 429 after limit, got %d", w.Code)
	}
}

// TestByAPIKey verifies the ByAPIKey convenience wrapper hashes the raw key
// before using it as the Valkey key, and enforces rate limiting correctly.
func TestByAPIKey(t *testing.T) {
	const rawKey = "raw-secret-key-123"
	const limit = 2

	rl, mr := newTestRateLimiter(t)

	gin.SetMode(gin.TestMode)
	r := gin.New()
	r.Use(func(c *gin.Context) {
		c.Set(ContextKeyAPIKey, rawKey)
		c.Next()
	})
	r.Use(ByAPIKey(rl, limit))
	r.GET("/test", func(c *gin.Context) { c.Status(http.StatusOK) })

	for i := 0; i < limit; i++ {
		w := doRequest(r)
		if w.Code != http.StatusOK {
			t.Fatalf("ByAPIKey request %d: expected 200, got %d", i+1, w.Code)
		}
	}
	w := doRequest(r)
	if w.Code != http.StatusTooManyRequests {
		t.Fatalf("ByAPIKey: expected 429 after limit, got %d", w.Code)
	}

	// Assert that the raw key was NOT stored in Valkey, and that the hashed
	// form IS present — confirming ByAPIKey hashes the key before use.
	hash := sha256.Sum256([]byte(rawKey))
	expectedValkeyKey := keyPrefixAPIKey + fmt.Sprintf("%x", hash)

	allKeys := mr.Keys()
	for _, k := range allKeys {
		if k == rawKey {
			t.Errorf("raw API key %q must not appear as a Valkey key", rawKey)
		}
	}
	found := false
	for _, k := range allKeys {
		if k == expectedValkeyKey {
			found = true
			break
		}
	}
	if !found {
		t.Errorf("expected hashed Valkey key %q to be present; keys in store: %v", expectedValkeyKey, allKeys)
	}
}

// TestNoKeyUsesFallbackKey verifies that when the key function returns "" the
// middleware falls back to an IP-based key and still enforces rate limiting,
// rather than silently passing the request through (fail-open).
func TestNoKeyUsesFallbackKey(t *testing.T) {
	rl, _ := newTestRateLimiter(t)

	const limit = 2
	mw := RateLimitMiddleware(rl, limit, func(c *gin.Context) string {
		return "" // no key — simulates identity lookup miss
	})
	r := newRateLimitRouter(mw)

	// Requests up to the limit should succeed (fallback key is rate-limited).
	for i := 0; i < limit; i++ {
		w := doRequest(r)
		if w.Code != http.StatusOK {
			t.Fatalf("fallback key: request %d expected 200, got %d", i+1, w.Code)
		}
	}

	// Once the fallback key's limit is exhausted the request must be rejected.
	w := doRequest(r)
	if w.Code != http.StatusTooManyRequests {
		t.Fatalf("fallback key: expected 429 after limit, got %d", w.Code)
	}
}

// TestResetHeaderIsUnixTimestamp verifies that X-RateLimit-Reset looks like a
// reasonable Unix timestamp (within a couple of minutes of now).
func TestResetHeaderIsUnixTimestamp(t *testing.T) {
	rl, _ := newTestRateLimiter(t)

	mw := RateLimitMiddleware(rl, 10, func(c *gin.Context) string {
		return "raven:rl:test:reset-ts"
	})
	r := newRateLimitRouter(mw)

	w := doRequest(r)
	if w.Code != http.StatusOK {
		t.Fatalf("expected 200, got %d", w.Code)
	}

	resetStr := w.Header().Get("X-RateLimit-Reset")
	resetTs, err := strconv.ParseInt(resetStr, 10, 64)
	if err != nil {
		t.Fatalf("X-RateLimit-Reset is not a valid int64: %q", resetStr)
	}

	now := time.Now().Unix()
	if resetTs < now || resetTs > now+120 {
		t.Errorf("X-RateLimit-Reset %d is not within [now, now+120] (%d)", resetTs, now)
	}
}

package middleware

import (
	"context"
	"crypto/sha256"
	"fmt"
	"log/slog"
	"net/http"
	"strconv"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/redis/go-redis/v9"
)

// Context keys used by upstream JWT/auth middleware to store identity values.
const (
	ContextKeyUserID = "user_id"
	ContextKeyOrgID  = "org_id"
	ContextKeyAPIKey = "api_key"
)

// Valkey key prefixes for each rate-limit scope.
const (
	keyPrefixAPIKey = "raven:rl:apikey:"
	keyPrefixUser   = "raven:rl:user:"
	keyPrefixOrg    = "raven:rl:org:"
)

// slidingWindowLua is an atomic Lua script that implements a sliding-window
// counter using a Valkey sorted set.
//
// KEYS[1] — the rate-limit key
// ARGV[1] — current time in milliseconds (Unix epoch)
// ARGV[2] — window size in milliseconds
// ARGV[3] — request limit
//
// Returns a three-element array: {current_count, remaining, oldest_ms}.
//   - Admitted:  remaining >= 0  (0 means the last slot was just consumed)
//   - Rejected:  remaining == -1 (count >= limit, request was NOT recorded)
//   - oldest_ms: Unix timestamp in milliseconds of the oldest surviving hit,
//     or 0 if the set is empty. Callers use this to compute the accurate reset
//     time: oldest_ms + window_ms gives the moment the oldest hit expires.
const slidingWindowLua = `
local key    = KEYS[1]
local now    = tonumber(ARGV[1])
local window = tonumber(ARGV[2])
local limit  = tonumber(ARGV[3])
redis.call('ZREMRANGEBYSCORE', key, 0, now - window)
local count = redis.call('ZCARD', key)
local oldest = 0
local oldest_entry = redis.call('ZRANGE', key, 0, 0, 'WITHSCORES')
if #oldest_entry > 0 then
  oldest = tonumber(oldest_entry[2])
end
if count < limit then
  redis.call('ZADD', key, now, now .. math.random())
  redis.call('EXPIRE', key, math.ceil(window/1000) + 1)
  return {count + 1, limit - count - 1, oldest}
end
return {count, -1, oldest}
`

// RateLimiter holds the Valkey client and logger used by rate-limit middleware.
type RateLimiter struct {
	client redis.Cmdable
	logger *slog.Logger
}

// NewRateLimiter constructs a RateLimiter from any redis.Cmdable (real client
// or miniredis stub).
func NewRateLimiter(client redis.Cmdable, logger *slog.Logger) *RateLimiter {
	if logger == nil {
		logger = slog.Default()
	}
	return &RateLimiter{client: client, logger: logger}
}

// rateLimitResult is the decoded response from the Lua script.
type rateLimitResult struct {
	count     int64
	remaining int64
	admitted  bool
	// resetAt is the Unix timestamp (seconds) at which the oldest in-window hit
	// expires, i.e. when the rate-limit counter first drops.  Falls back to
	// now+window when Valkey is unavailable or the window is empty.
	resetAt int64
}

// redactKey returns a safe representation of a rate-limit key for logging.
// It shows only the first 8 characters followed by "..." to avoid leaking
// user identity (user IDs, org IDs, hashed API keys) into log sinks.
func redactKey(key string) string {
	const maxVisible = 8
	if len(key) <= maxVisible {
		return key
	}
	return key[:maxVisible] + "..."
}

// check runs the sliding-window Lua script against Valkey and returns the
// result.  On any Valkey error the request is admitted (fail-open) and the
// error is logged as a warning.
func (rl *RateLimiter) check(ctx context.Context, key string, limit int, windowMs int64) rateLimitResult {
	now := time.Now().UnixMilli()
	fallbackResetAt := time.Now().Add(time.Duration(windowMs) * time.Millisecond).Unix()

	// Apply a short timeout to the Valkey call so a slow/unavailable server
	// does not stall the request indefinitely.
	callCtx, cancel := context.WithTimeout(ctx, 500*time.Millisecond)
	defer cancel()

	script := redis.NewScript(slidingWindowLua)
	res, err := script.Run(callCtx, rl.client,
		[]string{key},
		strconv.FormatInt(now, 10),
		strconv.FormatInt(windowMs, 10),
		strconv.Itoa(limit),
	).Int64Slice()

	if err != nil {
		rl.logger.WarnContext(ctx, "rate limiter: valkey unavailable, allowing request",
			slog.String("key", redactKey(key)),
			slog.String("error", err.Error()),
		)
		// Fail-open: treat as admitted with full remaining quota.
		return rateLimitResult{count: 0, remaining: int64(limit), admitted: true, resetAt: fallbackResetAt}
	}

	count := res[0]
	remaining := res[1]
	oldestMs := res[2]

	// Compute the precise reset time: the oldest surviving hit expires at
	// oldest_ms + window_ms.  When the window is empty (oldestMs == 0) fall
	// back to now + window.
	var resetAt int64
	if oldestMs > 0 {
		resetAt = (oldestMs + windowMs) / 1000
	} else {
		resetAt = fallbackResetAt
	}

	// remaining == -1 is the sentinel the Lua script uses for "rejected".
	admitted := remaining >= 0
	if remaining < 0 {
		remaining = 0 // clamp for header display
	}
	return rateLimitResult{count: count, remaining: remaining, admitted: admitted, resetAt: resetAt}
}

// fallbackKey builds a rate-limit key from the request's remote address so
// that anonymous or unidentified callers are still rate-limited rather than
// silently bypassing the limiter.
const keyPrefixFallback = "raven:rl:fallback:"

// fallbackLogSeen deduplicates the "identity lookup missed" warning so it fires
// at most once per IP per 5-minute window rather than on every request.
var fallbackLogSeen sync.Map

// RateLimitMiddleware is the generic Gin middleware factory.
//
//   - limit    — maximum requests per minute for this scope
//   - keyFn    — extracts the rate-limit key from the request context;
//     returning "" means identity could not be determined; a fallback
//     IP-based key is used instead so the limiter is never silently skipped.
func RateLimitMiddleware(rl *RateLimiter, limit int, keyFn func(*gin.Context) string) gin.HandlerFunc {
	const windowMs = int64(60_000) // 1 minute sliding window

	return func(c *gin.Context) {
		key := keyFn(c)
		if key == "" {
			// Identity lookup returned no key — fall back to the client IP so
			// the limiter still applies.  Log a warning, but deduplicate per IP
			// to avoid flooding logs under sustained anonymous traffic.
			ip := c.ClientIP()
			const logTTL = 5 * time.Minute
			now := time.Now()
			if v, loaded := fallbackLogSeen.LoadOrStore(ip, now); loaded {
				if now.Sub(v.(time.Time)) >= logTTL {
					// Entry is stale — refresh and log again.
					fallbackLogSeen.Store(ip, now)
					rl.logger.WarnContext(c.Request.Context(),
						"rate limiter: identity lookup missed, using IP fallback",
						slog.String("ip", ip),
						slog.String("path", c.FullPath()),
					)
				}
				// else: recently logged for this IP — stay silent
			} else {
				// First time we've seen this IP fall back — log immediately.
				rl.logger.WarnContext(c.Request.Context(),
					"rate limiter: identity lookup missed, using IP fallback",
					slog.String("ip", ip),
					slog.String("path", c.FullPath()),
				)
			}
			key = keyPrefixFallback + ip
		}

		result := rl.check(c.Request.Context(), key, limit, windowMs)

		// Always set informational headers.
		c.Header("X-RateLimit-Limit", strconv.Itoa(limit))
		c.Header("X-RateLimit-Remaining", strconv.FormatInt(result.remaining, 10))
		c.Header("X-RateLimit-Reset", strconv.FormatInt(result.resetAt, 10))

		if !result.admitted {
			retryAfter := result.resetAt - time.Now().Unix()
			if retryAfter < 1 {
				retryAfter = 1
			}
			c.Header("Retry-After", strconv.FormatInt(retryAfter, 10))
			c.AbortWithStatusJSON(http.StatusTooManyRequests, gin.H{
				"error":       "rate_limit_exceeded",
				"retry_after": retryAfter,
			})
			return
		}

		c.Next()
	}
}

// apiKeyHash returns the SHA-256 hex digest of an API key, used as the Valkey
// key suffix so that raw secrets are never stored in Valkey.
func apiKeyHash(apiKey string) string {
	h := sha256.Sum256([]byte(apiKey))
	return fmt.Sprintf("%x", h)
}

// ByAPIKey returns a Gin middleware that rate-limits by API key.
// The raw API key is read from gin.Context key ContextKeyAPIKey and hashed
// with SHA-256 before being used as the Valkey key suffix.
func ByAPIKey(rl *RateLimiter, limit int) gin.HandlerFunc {
	return RateLimitMiddleware(rl, limit, func(c *gin.Context) string {
		raw, ok := c.Get(ContextKeyAPIKey)
		if !ok {
			return ""
		}
		key, ok := raw.(string)
		if !ok || key == "" {
			return ""
		}
		return keyPrefixAPIKey + apiKeyHash(key)
	})
}

