package migrations_test

import (
	"context"
	"database/sql"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"testing"
	"time"

	_ "github.com/lib/pq"
	"github.com/pressly/goose/v3"
	"github.com/testcontainers/testcontainers-go"
	"github.com/testcontainers/testcontainers-go/wait"
)

const (
	testDBUser = "raven_test"
	testDBPass = "raven_test_pass"
	testDBName = "raven_test"
)

// allExpectedTables lists every table the migrations should create.
var allExpectedTables = []string{
	"organizations",
	"users",
	"workspaces",
	"workspace_members",
	"knowledge_bases",
	"documents",
	"sources",
	"chunks",
	"embeddings",
	"llm_provider_configs",
	"api_keys",
	"chat_sessions",
	"chat_messages",
	"processing_events",
}

// rlsTables are the tables that must have RLS enabled (all tables with org_id).
var rlsTables = []string{
	"users",
	"workspaces",
	"workspace_members",
	"knowledge_bases",
	"documents",
	"sources",
	"chunks",
	"embeddings",
	"llm_provider_configs",
	"api_keys",
	"chat_sessions",
	"chat_messages",
	"processing_events",
}

// allExpectedTypes lists every custom ENUM type.
var allExpectedTypes = []string{
	"org_status",
	"user_status",
	"workspace_role",
	"kb_status",
	"processing_status",
	"source_type",
	"crawl_frequency",
	"chunk_type",
	"llm_provider",
	"provider_status",
	"api_key_status",
	"message_role",
}

// startPostgresContainer spins up a pgvector-enabled PostgreSQL container.
func startPostgresContainer(ctx context.Context, t *testing.T) (testcontainers.Container, string) {
	t.Helper()

	req := testcontainers.ContainerRequest{
		Image:        "pgvector/pgvector:pg17",
		ExposedPorts: []string{"5432/tcp"},
		Env: map[string]string{
			"POSTGRES_USER":     testDBUser,
			"POSTGRES_PASSWORD": testDBPass,
			"POSTGRES_DB":       testDBName,
		},
		WaitingFor: wait.ForLog("database system is ready to accept connections").
			WithOccurrence(2).
			WithStartupTimeout(60 * time.Second),
	}

