		raw, ok := c.Get(ContextKeyUserID)
		if !ok {
			return ""
		}
		id, ok := raw.(string)
		if !ok || id == "" {
			return ""
		}
		return keyPrefixUser + id
	}, keyPrefixUser+"fallback:")
